import secrets
import hashlib
from datetime import datetime, timedelta
from functools import wraps
from flask import Flask, request, jsonify

app = Flask(__name__)

# In-memory storage (use database in production)
users_db = {
    'admin': hashlib.sha256('password123'.encode()).hexdigest(),
    'user1': hashlib.sha256('mypassword'.encode()).hexdigest()
}

tokens_db = {}

TOKEN_EXPIRY_HOURS = 24


def generate_token():
    return secrets.token_urlsafe(32)


def verify_token(token):
    if token not in tokens_db:
        return None
    
    token_data = tokens_db[token]
    if datetime.now() > token_data['expires_at']:
        del tokens_db[token]
        return None
    
    return token_data['username']


def token_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers.get('Authorization')
        
        if not token:
            return jsonify({'error': 'Token is missing'}), 401
        
        if token.startswith('Bearer '):
            token = token[7:]
        
        username = verify_token(token)
        if not username:
            return jsonify({'error': 'Invalid or expired token'}), 401
        
        return f(username=username, *args, **kwargs)
    
    return decorated_function


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    
    if not data or 'username' not in data or 'password' not in data:
        return jsonify({'error': 'Username and password required'}), 400
    
    username = data['username']
    password = data['password']
    
    password_hash = hashlib.sha256(password.encode()).hexdigest()
    
    if username not in users_db or users_db[username] != password_hash:
        return jsonify({'error': 'Invalid credentials'}), 401
    
    token = generate_token()
    expires_at = datetime.now() + timedelta(hours=TOKEN_EXPIRY_HOURS)
    
    tokens_db[token] = {
        'username': username,
        'created_at': datetime.now(),
        'expires_at': expires_at
    }
    
    return jsonify({
        'token': token,
        'expires_at': expires_at.isoformat(),
        'message': 'Login successful'
    }), 200


@app.route('/logout', methods=['POST'])
@token_required
def logout(username):
    token = request.headers.get('Authorization')
    if token.startswith('Bearer '):
        token = token[7:]
    
    if token in tokens_db:
        del tokens_db[token]
    
    return jsonify({'message': 'Logout successful'}), 200


@app.route('/protected', methods=['GET'])
@token_required
def protected_route(username):
    return jsonify({
        'message': 'This is a protected endpoint',
        'user': username,
        'data': 'Sensitive information'
    }), 200


@app.route('/profile', methods=['GET'])
@token_required
def get_profile(username):
    return jsonify({
        'username': username,
        'message': f'Welcome {username}!'
    }), 200


@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    
    if not data or 'username' not in data or 'password' not in data:
        return jsonify({'error': 'Username and password required'}), 400
    
    username = data['username']
    password = data['password']
    
    if username in users_db:
        return jsonify({'error': 'Username already exists'}), 409
    
    password_hash = hashlib.sha256(password.encode()).hexdigest()
    users_db[username] = password_hash
    
    return jsonify({'message': 'User registered successfully'}), 201


@app.route('/verify-token', methods=['GET'])
@token_required
def verify_token_endpoint(username):
    return jsonify({
        'valid': True,
        'username': username
    }), 200


